#define BS BLOCK_SIZE

#define AA(_i,_j) a[offset*size+_i*size+_j+offset]
#define BB(_i,_j) a[_i*size+_j]

kernel void lud_diagonal(global float* a, local float* temp, const int size, const int offset)
{
    int i = get_global_id(0);
    int j, k;

    if (i >= BS) return;

    for (j = i; j < BS; j++) {
        for (k = 0; k < i; k++) {
            AA(i,j) = AA(i,j) - AA(i,k) * AA(k,j);
        }
    }

    float temp_val = 1.f/AA(i,i);
    for (j = i+1; j < BS; j++) {
        for (k = 0; k < i; k++) {
            AA(j,i) = AA(j,i) - AA(j,k) * AA(k,i);
        }
        AA(j,i) = AA(j,i)*temp_val;
    }
}

kernel void lud_perimeter(global float* a, local float* temp_top, local float* temp_left, local float* temp_diag, const int size, const int offset)
{
    int idx = get_global_id(0);
    int i, j, k, i_global, j_global, i_here, j_here;
    float sum;

    int chunks_in_inter_row = (size - offset - BS) / BS;

    if (idx < BS * chunks_in_inter_row) {
        int chunk_idx = idx / BS;
        int elem_idx = idx % BS;

        float temp[BS*BS];

        for (i = 0; i < BS; i++) {
            for (j = 0; j < BS; j++){
                temp[i*BS + j] = a[size*(i + offset) + offset + j];
            }
        }

        i_global = offset;
        j_global = offset + BS * (chunk_idx + 1);

        j = elem_idx;
        for (i = 0; i < BS; i++) {
            sum = 0.f;
            for (k = 0; k < i; k++) {
                sum += temp[BS*i + k] * BB((i_global + k), (j_global + j));
            }
            i_here = i_global + i;
            j_here = j_global + j;
            BB(i_here, j_here) = BB(i_here, j_here) - sum;
        }
    } else if (idx < BS * 2 * chunks_in_inter_row) {
        int chunk_idx = (idx - BS * chunks_in_inter_row) / BS;
        int elem_idx = (idx - BS * chunks_in_inter_row) % BS;

        float temp[BS*BS];

        for (i = 0; i < BS; i++) {
            for (j = 0; j < BS; j++){
                temp[i*BS + j] = a[size*(i + offset) + offset + j];
            }
        }

        j_global = offset;
        i_global = offset + BS * (chunk_idx + 1);

        i = elem_idx;
        for (j = 0; j < BS; j++) {
            sum = 0.f;
            for (k = 0; k < j; k++) {
                sum += BB((i_global + i), (j_global + k)) * temp[BS*k + j];
            }
            i_here = i_global + i;
            j_here = j_global + j;
            a[size*i_here + j_here] = (a[size*i_here + j_here] - sum) / a[size*(offset + j) + offset + j];
        }
    }
}

kernel void lud_internal(global float* a, local float* temp_top, local float* temp_left, const int size, const int offset)
{
    int i_local = get_global_id(0) % BS;
    int j_local = get_global_id(0) / BS;
    int chunk_row = get_global_id(1) % ((size - offset - BS) / BS);
    int chunk_col = get_global_id(1) / ((size - offset - BS) / BS);

    int chunks_in_inter_row = (size - offset - BS) / BS;

    if (chunk_row >= chunks_in_inter_row || chunk_col >= chunks_in_inter_row) return;

    int i_global = offset + BS * (1 + chunk_row);
    int j_global = offset + BS * (1 + chunk_col);

    float sum[BS];
    for (int idx = 0; idx < BS; idx++) sum[idx] = 0.f;

    for (i = 0; i < BS; i++) {
        for (j = 0; j < BS; j++){
            temp_top[i*BS + j] = a[size*(i + offset) + j + j_global];
            temp_left[i*BS + j] = a[size*(i + i_global) + offset + j];
        }
    }

    for (i = 0; i < BS; i) {
        for (k = 0; k < BS; k++) {
            for (j = 0; j < BS; j++) {
                sum[j] += temp_left[BS*i + k] * temp_top[BS*k + j];
            }
        }
        for (j = 0; j < BS; j++) {
            BB((i + i_global), (j + j_global)) -= sum[j];
            sum[j] = 0.f;
        }
        i++;
    }
}
